// ── Entrada: aceita body direto ou aninhado ──────────────────
const body = $json.body || $json;

const rawPhone = (body.phone || body.whatsapp || '').toString();
const name     = (body.name  || 'Lead').trim();
const segment  = body.segment    || '';
const invest   = body.investment || '';
const goal     = body.goal       || '';
const source   = body.source     || 'hs-visual-quiz';
const ts       = body.timestamp  || new Date().toISOString();

// ── Normalização do telefone ──────────────────────────────────
// 1. Remove tudo que não for dígito
let phone = rawPhone.replace(/\D/g, '');
// 2. Remove zero à esquerda  (ex: 011... → 11...)
phone = phone.replace(/^0+/, '');
// 3. Adiciona DDI 55 se não tiver
if (!phone.startsWith('55')) {
  phone = '55' + phone;
}

// ── Primeiro nome ─────────────────────────────────────────────
const firstName = name.split(' ')[0];

// ── Mapa de segmentos ─────────────────────────────────────────
const segMap = {
  'Imobiliário de Luxo'          : 'imóveis de luxo',
  'Saúde Premium'                : 'saúde premium',
  'Corporate / B2B'              : 'negócios corporativos',
  'Lifestyle / Varejo Alto Padrão': 'lifestyle e varejo premium',
  'Outro'                        : 'seu negócio'
};
const segLabel = segMap[segment] || segment || 'seu negócio';

// ── Mensagem personalizada para o lead ───────────────────────
const message =
  `Olá ${firstName}! 👋\n\n` +
  `Aqui é o Helder da *HS Visual*. Recebi seu interesse em estratégias para *${segLabel}* e fiquei animado!\n\n` +
  `Você está no lugar certo. Trabalhamos exclusivamente com marcas Triple A que querem dominar o mercado com conteúdo de elite.\n\n` +
  `📊 *Próximo passo:*\n` +
  `Vou analisar seu perfil e te enviar um diagnóstico personalizado em até 24h.\n\n` +
  `Enquanto isso, me conta: qual é o maior desafio do seu marketing hoje?\n\n` +
  `_Helder Show — HS Visual_\n` +
  `_Jundiaí/SP | hsvisual.com_`;

// ── Mensagem de alerta para o Helder ─────────────────────────
const alertMsg =
  `🚀 Novo Lead Qualificado: ${name} do setor ${segment} acabou de finalizar o Quiz!\n\n` +
  `📱 WhatsApp: ${phone}\n` +
  `💰 Investimento: ${invest}\n` +
  `🎯 Objetivo: ${goal}\n` +
  `⏰ ${new Date(ts).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })}`;

return [{
  json: {
    name,
    firstName,
    phoneRaw    : rawPhone,
    phone,
    segment,
    segLabel,
    investment  : invest,
    goal,
    source,
    timestamp   : ts,
    capturedAt  : new Date().toISOString(),
    message,
    alertMsg
  }
}];
